Below is an example of how you could define a wrapper class for `SDL_Texture`:

```cpp
#include <SDL.h>

class Texture {
public:
    // Construct an empty texture.
    Texture() : sdlTexture(nullptr) {}

    // Disallow copy construction and assignment for safety, textures are often non-copyable resources.
    Texture(const Texture&) = delete;
    Texture& operator=(const Texture&) = delete;

    // Implement moving semantics to allow transferring ownership of the texture.
    Texture(Texture&& other) noexcept : sdlTexture(other.sdlTexture) {
        other.sdlTexture = nullptr;
    }

    Texture& operator=(Texture&& other) noexcept {
        if (this != &other) {
            Free(); // Free existing texture if any
            sdlTexture = other.sdlTexture;
            other.sdlTexture = nullptr;
        }
        return *this;
    }

    // Destructor
    virtual ~Texture() {
        Free();
    }

    // Member function to create a texture from a file
    bool LoadFromFile(SDL_Renderer* renderer, const std::string& filePath) {
        // You would typically create a texture using SDL_Image or similar library here.
        // For example:
        SDL_Surface* surface = IMG_Load(filePath.c_str()); // You need to #include <SDL_image.h> for IMG_Load.
        if (!surface) {
            return false;
        }

        // Free existing texture if any
        Free();

        sdlTexture = SDL_CreateTextureFromSurface(renderer, surface);
        // Don't forget to free the loaded surface
        SDL_FreeSurface(surface);

        return sdlTexture != nullptr;
    }

    // Member function to free the texture
    void Free() {
        if (sdlTexture) {
            SDL_DestroyTexture(sdlTexture);
            sdlTexture = nullptr;
        }
    }

    // Get a pointer to the underlying SDL_Texture
